#include <stdio.h>
#include <stdlib.h>

typedef struct Node {int v; struct Node* next;} Node;

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d", &N, &M);
        int *indeg = calloc(N, sizeof(int));
        int *outdeg = calloc(N, sizeof(int));
        Node **adj = calloc(N, sizeof(Node*));
        for(int i=0;i<M;i++){
            int a,b; scanf("%d %d", &a, &b); a--; b--;
            Node* nd = malloc(sizeof(Node)); nd->v=b; nd->next=adj[a]; adj[a]=nd;
            indeg[b]++; outdeg[a]++;
        }
        // Kahn's algorithm
        int *queue = malloc(N*sizeof(int)); int qs=0, qe=0;
        for(int i=0;i<N;i++) if(indeg[i]==0) queue[qe++]=i;
        int visited=0;
        while(qs<qe){
            int u=queue[qs++]; visited++;
            for(Node* p=adj[u]; p; p=p->next){
                int v=p->v; indeg[v]--; if(indeg[v]==0) queue[qe++]=v;
            }
        }
        if(visited!=N){
            printf("-1\n");
        }else{
            int sinks=0; for(int i=0;i<N;i++) if(outdeg[i]==0) sinks++;
            printf("%d\n", sinks-1);
        }
        // free memory
        for(int i=0;i<N;i++) while(adj[i]){Node* tmp=adj[i]; adj[i]=tmp->next; free(tmp);}        
        free(adj); free(indeg); free(outdeg); free(queue);
    }
    return 0;
}

