const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let results = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const M = input[idx++];
  const adj = Array.from({ length: N }, () => []);
  const indeg = new Array(N).fill(0);
  const outdeg = new Array(N).fill(0);
  for (let i = 0; i < M; i++) {
    const a = input[idx++] - 1;
    const b = input[idx++] - 1;
    adj[a].push(b);
    indeg[b]++;
    outdeg[a]++;
  }
  const queue = [];
  for (let i = 0; i < N; i++) if (indeg[i] === 0) queue.push(i);
  let head = 0;
  let visited = 0;
  while (head < queue.length) {
    const u = queue[head++];
    visited++;
    for (const v of adj[u]) {
      indeg[v]--;
      if (indeg[v] === 0) queue.push(v);
    }
  }
  if (visited !== N) {
    results.push('-1');
  } else {
    let sinks = 0;
    for (let d of outdeg) if (d === 0) sinks++;
    results.push(String(sinks - 1));
  }
}
console.log(results.join('\n'));
